import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertFailsWith

class PricingTest {
    @Test
    fun `applies the discount only above the threshold`() {
        assertEquals(90, applyDiscount(100, threshold = 50))
    }

    @Test
    fun `rejects a negative amount`() {
        assertFailsWith<IllegalArgumentException> { applyDiscount(-1, threshold = 50) }
    }
}

class FakeUserRepository : UserRepository {
    private val store = mutableMapOf<Long, User>()
    override fun save(user: User) { store[user.id] = user }
    override fun find(id: Long): User? = store[id]
}

@Test
fun `save then find returns the same user`() {
    val repo = FakeUserRepository()
    repo.save(User(1, "sany@mail.dev"))
    assertEquals("sany@mail.dev", repo.find(1)?.email)
}

import kotlinx.coroutines.test.runTest
import kotlinx.coroutines.test.advanceTimeBy

@Test
fun `emits a value after the debounce delay`() = runTest {
    val results = mutableListOf<Int>()
    val job = launch { source().debounce(300).toList(results) }
    advanceTimeBy(301)
    assertEquals(listOf(42), results)
    job.cancel()
}

